noncompliant:
class BadClass {
public:
    ~BadClass() noexcept(false) {  // Noncompliant: allows exceptions
        throw std::runtime_error("Error in destructor");
    }
};

class AnotherBadClass {
public:
    ~AnotherBadClass() {
        // Noncompliant: might throw
        resource_.close(); // This might throw
        if (error_condition) {
            throw std::runtime_error("Cleanup failed"); // Noncompliant
        }
    }
};

compliant:
class GoodClass {
public:
    ~GoodClass() noexcept {  // Compliant: explicitly noexcept
        try {
            resource_.close(); // Wrap risky operations in try-catch
        } catch (...) {
            // Log error but don't rethrow
        }
    }
};

class SafeClass {
public:
    ~SafeClass() {  // Compliant: only safe operations
        // Perform cleanup that cannot throw
        reset_member_variables();
        release_resources_safely();
    }
};
